### Step 6: Create server-side IShipmentService implementation

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetShipmentsAsync(string? statusFilter = null)
    {
        var query = db.Shipments.AsQueryable();
        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, true, out var status))
            query = query.Where(s => s.Status == status);
        return await query.OrderByDescending(s => s.CreatedAt).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment?> GetShipmentByIdAsync(int id)
    {
        return await db.Shipments.FindAsync(id);
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        shipment.CreatedAt = DateTime.UtcNow;
        if (string.IsNullOrEmpty(shipment.TrackingNumber))
            shipment.TrackingNumber = $"SHP-{Guid.NewGuid().ToString("N")[..10].ToUpperInvariant()}";
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return shipment;
    }

    public async Task UpdateShipmentAsync(Shipment shipment)
    {
        db.Shipments.Update(shipment);
        await db.SaveChangesAsync();
    }
}
```

