@page "/track/{TrackingNumber}"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services

<PageTitle>Track Shipment - @TrackingNumber</PageTitle>

<div class="container mt-4">
    <h2>Shipment Tracking</h2>

    @if (loading)
    {
        <div class="d-flex align-items-center mt-3">
            <div class="spinner-border spinner-border-sm me-2" role="status"></div>
            <span>Looking up shipment...</span>
        </div>
    }
    else if (shipment is null)
    {
        <div class="alert alert-warning mt-3">
            <strong>Not found.</strong> No shipment matches tracking number <code>@TrackingNumber</code>.
        </div>
        <a href="/" class="btn btn-outline-primary">Try Another</a>
    }
    else
    {
        <div class="card mt-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>@shipment.TrackingNumber</strong>
                <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <dl>
                            <dt>Origin</dt>
                            <dd>@shipment.Origin</dd>
                            <dt>Destination</dt>
                            <dd>@shipment.Destination</dd>
                            <dt>Recipient</dt>
                            <dd>@(shipment.RecipientName ?? "—")</dd>
                        </dl>
                    </div>
                    <div class="col-md-6">
                        <dl>
                            <dt>Created</dt>
                            <dd>@shipment.CreatedAt.ToString("MMM dd, yyyy HH:mm") UTC</dd>
                            <dt>Estimated Delivery</dt>
                            <dd>
                                @if (shipment.EstimatedDelivery.HasValue)
                                {
                                    @shipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")
                                }
                                else
                                {
                                    <span class="text-muted">Not yet estimated</span>
                                }
                            </dd>
                        </dl>
                    </div>
                </div>
                @if (!string.IsNullOrWhiteSpace(shipment.Notes))
                {
                    <hr />
                    <p><strong>Notes:</strong> @shipment.Notes</p>
                }
            </div>
        </div>

        <div class="mt-3">
            <h5>Delivery Progress</h5>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgressPercent(shipment.Status))%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>

        <a href="/" class="btn btn-outline-primary mt-3">Track Another</a>
    }
</div>

@code {
    [Parameter] public string TrackingNumber { get; set; } = string.Empty;
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private Shipment? shipment;
    private bool loading = true;

    protected override async Task OnParametersSetAsync()
    {
        loading = true;
        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(TrackingNumber);
        }
        catch
        {
            shipment = null;
        }
        loading = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-warning text-dark"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}

@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]

<PageTitle>Shipments - Dispatch Dashboard</PageTitle>

<div class="container mt-4">
    <div class="d-flex justify-content-between align-items-center">
        <h2>Shipments</h2>
        <a href="shipments/new" class="btn btn-success">+ New Shipment</a>
    </div>

    <div class="row mt-3 mb-3">
        <div class="col-md-4">
            <select class="form-select" @bind="selectedStatus" @bind:after="LoadShipments">
                <option value="">All Statuses</option>
                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@status">@status</option>
                }
            </select>
        </div>
        <div class="col-md-4">
            <input type="text" class="form-control" placeholder="Search by tracking # or destination..."
                   @bind="searchTerm" @bind:event="oninput" />
        </div>
    </div>

    @if (loading)
    {
        <div class="d-flex align-items-center">
            <div class="spinner-border spinner-border-sm me-2" role="status"></div>
            <span>Loading shipments...</span>
        </div>
    }
    else if (FilteredShipments.Count == 0)
    {
        <div class="alert alert-info">No shipments found.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th @onclick='() => SortBy("TrackingNumber")' style="cursor:pointer">
                            Tracking # @SortIndicator("TrackingNumber")
                        </th>
                        <th @onclick='() => SortBy("Destination")' style="cursor:pointer">
                            Destination @SortIndicator("Destination")
                        </th>
                        <th @onclick='() => SortBy("Status")' style="cursor:pointer">
                            Status @SortIndicator("Status")
                        </th>
                        <th @onclick='() => SortBy("EstimatedDelivery")' style="cursor:pointer">
                            Est. Delivery @SortIndicator("EstimatedDelivery")
                        </th>
                        <th>Recipient</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var s in FilteredShipments)
                    {
                        <tr>
                            <td><a href="track/@Uri.EscapeDataString(s.TrackingNumber)">@s.TrackingNumber</a></td>
                            <td>@s.Destination</td>
                            <td><span class="badge @GetBadgeClass(s.Status)">@s.Status</span></td>
                            <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                            <td>@(s.RecipientName ?? "—")</td>
                            <td>
                                <a href="shipments/edit/@s.Id" class="btn btn-sm btn-outline-primary">Edit</a>
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
        <p class="text-muted">Showing @FilteredShipments.Count of @shipments.Count shipments</p>
    }
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private List<Shipment> shipments = [];
    private bool loading = true;
    private string selectedStatus = "";
    private string searchTerm = "";
    private string sortColumn = "CreatedAt";
    private bool sortAscending;

    private List<Shipment> FilteredShipments
    {
        get
        {
            var result = shipments.AsEnumerable();
            if (!string.IsNullOrWhiteSpace(searchTerm))
            {
                var term = searchTerm.Trim();
                result = result.Where(s =>
                    s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                    s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase));
            }

            result = sortColumn switch
            {
                "TrackingNumber" => sortAscending ? result.OrderBy(s => s.TrackingNumber) : result.OrderByDescending(s => s.TrackingNumber),
                "Destination" => sortAscending ? result.OrderBy(s => s.Destination) : result.OrderByDescending(s => s.Destination),
                "Status" => sortAscending ? result.OrderBy(s => s.Status) : result.OrderByDescending(s => s.Status),
                "EstimatedDelivery" => sortAscending ? result.OrderBy(s => s.EstimatedDelivery) : result.OrderByDescending(s => s.EstimatedDelivery),
                _ => result
            };

            return result.ToList();
        }
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        try
        {
            shipments = await ShipmentService.GetShipmentsAsync(
                string.IsNullOrEmpty(selectedStatus) ? null : selectedStatus);
        }
        catch
        {
            shipments = [];
        }
        loading = false;
    }

    private void SortBy(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private string SortIndicator(string column) =>
        sortColumn != column ? "" : sortAscending ? "▲" : "▼";

    private static string GetBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-warning text-dark"
    };
}

@page "/shipments/new"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]

<PageTitle>Create Shipment</PageTitle>

<div class="container mt-4">
    <h2>Create New Shipment</h2>

    <EditForm Model="shipment" OnValidSubmit="HandleSubmit" FormName="CreateShipment">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="row mt-3">
            <div class="col-md-6 mb-3">
                <label class="form-label">Origin</label>
                <InputText class="form-control" @bind-Value="shipment.Origin" placeholder="City, Country" />
            </div>
            <div class="col-md-6 mb-3">
                <label class="form-label">Destination</label>
                <InputText class="form-control" @bind-Value="shipment.Destination" placeholder="City, Country" />
            </div>
        </div>

        <div class="row">
            <div class="col-md-6 mb-3">
                <label class="form-label">Recipient Name</label>
                <InputText class="form-control" @bind-Value="shipment.RecipientName" />
            </div>
            <div class="col-md-6 mb-3">
                <label class="form-label">Estimated Delivery</label>
                <InputDate class="form-control" @bind-Value="shipment.EstimatedDelivery" />
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label">Notes</label>
            <InputTextArea class="form-control" @bind-Value="shipment.Notes" rows="3" />
        </div>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        @if (!string.IsNullOrEmpty(successMessage))
        {
            <div class="alert alert-success">@successMessage</div>
        }

        <button type="submit" class="btn btn-primary" disabled="@submitting">
            @(submitting ? "Creating..." : "Create Shipment")
        </button>
        <a href="shipments" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
</div>

