@page "/"

<PageTitle>ShipmentTracker - Home</PageTitle>

<div class="container mt-4">
    <h1>Shipment Tracker</h1>
    <p class="lead">Track your shipments in real time. Enter your tracking number below to get started.</p>

    <div class="card mt-4">
        <div class="card-body">
            <h5 class="card-title">Track a Shipment</h5>
            <div class="input-group">
                <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-ABC1234567)"
                       @bind="trackingNumber" @bind:event="oninput"
                       @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="TrackShipment" disabled="@string.IsNullOrWhiteSpace(trackingNumber)">
                    Track
                </button>
            </div>
        </div>
    </div>

    <AuthorizeView>
        <Authorized>
            <div class="mt-4">
                <a href="shipments" class="btn btn-outline-primary me-2">View All Shipments</a>
                <a href="shipments/new" class="btn btn-outline-success">Create Shipment</a>
            </div>
        </Authorized>
        <NotAuthorized>
            <p class="mt-4 text-muted">
                <a href="Account/Login">Log in</a> to manage shipments.
            </p>
        </NotAuthorized>
    </AuthorizeView>
</div>

@code {
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private string? trackingNumber;

    private void TrackShipment()
    {
        if (!string.IsNullOrWhiteSpace(trackingNumber))
            Navigation.NavigateTo($"track/{Uri.EscapeDataString(trackingNumber.Trim())}");
    }

    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            TrackShipment();
    }
}

