            shipments = await ShipmentService.GetShipmentsAsync(
                string.IsNullOrEmpty(selectedStatus) ? null : selectedStatus);
        }
        catch
        {
            shipments = [];
        }
        loading = false;
    }

    private void SortBy(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private string SortIndicator(string column) =>
        sortColumn != column ? "" : sortAscending ? "▲" : "▼";

    private static string GetBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-warning text-dark"
    };
