                <label class="form-label">Tracking Number</label>
                <input class="form-control" value="@shipment.TrackingNumber" disabled />
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Origin</label>
                    <InputText class="form-control" @bind-Value="shipment.Origin" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Destination</label>
                    <InputText class="form-control" @bind-Value="shipment.Destination" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-4 mb-3">
                    <label class="form-label">Status</label>
                    <InputSelect class="form-select" @bind-Value="shipment.Status">
                        @foreach (var status in Enum.GetValues<ShipmentStatus>())
                        {
                            <option value="@status">@status</option>
                        }
                    </InputSelect>
                </div>
                <div class="col-md-4 mb-3">
                    <label class="form-label">Recipient Name</label>
                    <InputText class="form-control" @bind-Value="shipment.RecipientName" />
                </div>
                <div class="col-md-4 mb-3">
                    <label class="form-label">Estimated Delivery</label>
                    <InputDate class="form-control" @bind-Value="shipment.EstimatedDelivery" />
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label">Notes</label>
                <InputTextArea class="form-control" @bind-Value="shipment.Notes" rows="3" />
            </div>

            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }

            @if (!string.IsNullOrEmpty(successMessage))
            {
                <div class="alert alert-success">@successMessage</div>
            }

            <button type="submit" class="btn btn-primary" disabled="@submitting">
                @(submitting ? "Saving..." : "Save Changes")
            </button>
            <a href="shipments" class="btn btn-outline-secondary ms-2">Cancel</a>
        </EditForm>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private Shipment? shipment;
    private bool loading = true;
    private bool submitting;
    private string? errorMessage;
    private string? successMessage;

    protected override async Task OnParametersSetAsync()
    {
        loading = true;
        try
        {
            shipment = await ShipmentService.GetShipmentByIdAsync(Id);
        }
        catch
        {
            shipment = null;
        }
        loading = false;
    }

    private async Task HandleSubmit()
    {
        if (shipment is null) return;

        submitting = true;
        errorMessage = null;
        successMessage = null;

        try
        {
            await ShipmentService.UpdateShipmentAsync(shipment);
            successMessage = "Shipment updated successfully!";
            await Task.Delay(1000);
            Navigation.NavigateTo("shipments");
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to update: {ex.Message}";
        }

        submitting = false;
    }
}
```

