                Status = ShipmentStatus.InTransit,
                CreatedAt = DateTime.UtcNow.AddDays(-3),
                EstimatedDelivery = DateTime.UtcNow.AddDays(4),
                RecipientName = "Jane Smith",
                Notes = "Fragile — handle with care"
            },
            new Shipment
            {
                TrackingNumber = "SHP-DEMO000002",
                Origin = "Tokyo, Japan",
                Destination = "Sydney, Australia",
                Status = ShipmentStatus.OutForDelivery,
                CreatedAt = DateTime.UtcNow.AddDays(-5),
                EstimatedDelivery = DateTime.UtcNow.AddDays(1),
                RecipientName = "Carlos Rivera"
            },
            new Shipment
            {
                TrackingNumber = "SHP-DEMO000003",
                Origin = "Berlin, Germany",
                Destination = "São Paulo, Brazil",
                Status = ShipmentStatus.Pending,
                CreatedAt = DateTime.UtcNow.AddDays(-1),
                EstimatedDelivery = DateTime.UtcNow.AddDays(10),
                RecipientName = "Amara Okafor"
            },
            new Shipment
            {
                TrackingNumber = "SHP-DEMO000004",
